services: server: image: docker.io/awinterstein/habitica-server:latest restart: unless-stopped depends_on: mongo: condition: service_healthy environment: NODE_DB_URI: mongodb://{{ mongo_habitica_user }}:{{ mongo_habitica_password }}@mongo/habitica?authSource=habitica INVITE_ONLY: {{ invite_only }} EMAIL_SERVER_URL: {{ email_server_url }} EMAIL_SERVER_PORT: {{ email_server_port }} EMAIL_SERVER_AUTH_USER: {{ email_server_auth_user }} EMAIL_SERVER_AUTH_PASSWORD: {{ email_server_auth_password }} ADMIN_EMAIL: {{ admin_email }} container_name: '{{ INSTANCE_CODE }}_server' networks: - internal client: image: docker.io/awinterstein/habitica-client:latest restart: unless-stopped depends_on: - server ports: - '{{ PORT_HTTP }}:80' container_name: '{{ INSTANCE_CODE }}' networks: - internal - agz-proxy-network mongo: image: docker.io/mongo:latest restart: unless-stopped command: "bash -c "
 echo \"{{ mongo_keyfile_content }}\" > /etc/mongo-keyfile &&
 chown 999:999\ \ /etc/mongo-keyfile &&
 chmod 400 /etc/mongo-keyfile &&
 exec docker-entrypoint.sh mongod --replSet\ \ rs --bind_ip_all --port 27017 --keyFile /etc/mongo-keyfile
"
" environment: MONGO_INITDB_ROOT_USERNAME: {{ mongo_admin_user }} MONGO_INITDB_ROOT_PASSWORD: {{ mongo_admin_password }} MONGO_KEYFILE_CONTENT: {{ mongo_keyfile_content }} MONGO_HABITICA_USER: {{ mongo_habitica_user }} MONGO_HABITICA_PASSWORD: {{ mongo_habitica_password }} healthcheck: test: "mongosh --port 27017 --quiet -u "{{ mongo_admin_user }}" -p "{{ mongo_admin_password }}" --authenticationDatabase\ \ admin --eval "
 try {
 // 1. Hostname Fix
 const config = rs.conf();
 const currentHost\ \ = require('os').hostname() + ':27017';
 if (config.members[0].host !== currentHost) {
\ \ config.members[0].host = currentHost;
 rs.reconfig(config, { force: true });
 \ \ }

 // 2. User Creation Logic
 const targetDb = db.getSiblingDB('habitica');
 \ \ const hUser = process.env.MONGO_HABITICA_USER;
 const hPass = process.env.MONGO_HABITICA_PASSWORD;
\ 
 // We can only check/create users if we are Primary
 if (rs.isMaster().ismaster) {
\ \ if (!targetDb.getUser(hUser)) {
 print('Creating missing user ' + hUser + '...');
\ \ targetDb.createUser({ user: hUser, pwd: hPass, roles: ['readWrite'] });
 }
 \ \ // SUCCESS: User exists and we are Primary
 quit(0);
 } else {
 // We are\ \ not Primary yet (still electing), so we cannot confirm user exists.
 // Fail the check\ \ so the dependent app waits.
 print('Waiting for Primary state...');
 quit(1);
\ \ }
 } catch (err) {
 // If not initialized, initiate and FAIL this check so we wait\ \ for the next cycle
 try { 
 rs.initiate({ _id: 'rs', members: [{ _id: 0, host: require('os').hostname()\ \ + ':27017' }] }); 
 } catch (e) {}
 quit(1);
 }
"
" interval: 5s timeout: 10s retries: 20 volumes: - ./habitica_mongo_data:/data/db container_name: '{{ INSTANCE_CODE }}_mongo' networks: - internal networks: internal: driver: bridge agz-proxy-network: external: true
